#!/usr/bin/env python3
# scripts/check_runbook_links.py
# Verify every Prometheus alert has runbook_url pointing to existing file
import re, os, glob, sys
import yaml

ALERT_DIR = 'monitoring/alerts/'
RUNBOOK_DIR = 'runbooks/'

def load_alerts(path):
    with open(path) as f:
        data = yaml.safe_load(f)
    rules = []
    for group in data.get('groups', []):
        rules.extend(group.get('rules', []))
    return rules

def check_runbook_url(alert):
    name = alert.get('alert', '?')
    url = alert.get('annotations', {}).get('runbook_url', '')
    if not url:
        return f'{name}: missing runbook_url annotation'
    match = re.search(r'/runbooks/(.+\.md)', url)
    if not match:
        return f'{name}: runbook_url not pointing to /runbooks/*.md'
    rb_file = RUNBOOK_DIR + match.group(1)
    if not os.path.exists(rb_file):
        return f'{name}: runbook file not found: {rb_file}'
    return None

if __name__ == '__main__':
    errors = []
    for alert_file in glob.glob(ALERT_DIR + '*.yaml'):
        for alert in load_alerts(alert_file):
            err = check_runbook_url(alert)
            if err:
                errors.append(err)
    for e in errors:
        print(e)
    raise SystemExit(len(errors))

#!/usr/bin/env python3
# scripts/schedule_runbook_reviews.py
# Find runbooks overdue for review and open Jira tickets
import os, datetime

RUNBOOK_DIR = 'runbooks/'
REVIEW_INTERVAL_DAYS = 90

def get_last_reviewed(path):
    with open(path) as f:
        for line in f:
            if line.startswith('last_reviewed:'):
                return datetime.date.fromisoformat(line.split()[-1].strip())
    return None

def main():
    today = datetime.date.today()
    overdue = []
    for fname in os.listdir(RUNBOOK_DIR):
        if not fname.endswith('.md'):
            continue
        path = os.path.join(RUNBOOK_DIR, fname)
        reviewed = get_last_reviewed(path)
        if reviewed is None:
            overdue.append((fname, 'never reviewed'))
        elif (today - reviewed).days > REVIEW_INTERVAL_DAYS:
            age = (today - reviewed).days
            overdue.append((fname, f'{age}d since last review'))
    for fname, reason in overdue:
        print(f'OVERDUE: {fname} -- {reason}')
        # In production: create Jira ticket via REST API
    raise SystemExit(len(overdue))

if __name__ == '__main__':
    main()
